import{_ as a,o as i,c as t,a4 as l}from"./chunks/framework.Br660gtV.js";const p=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"CHANGELOG.md","filePath":"CHANGELOG.md"}'),r={name:"CHANGELOG.md"};function o(d,e,n,s,h,c){return i(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>All notable changes to this project will be documented in this file.</p><p>The format is based on <a href="https://keepachangelog.com/en/1.1.0/" target="_blank" rel="noreferrer">Keep a Changelog</a>, and this project adheres to <a href="https://semver.org/spec/v2.0.0.html" target="_blank" rel="noreferrer">Semantic Versioning</a>.</p><h2 id="_1-1-0-2026-07-23" tabindex="-1">[1.1.0] - 2026-07-23 <a class="header-anchor" href="#_1-1-0-2026-07-23" aria-label="Permalink to &quot;[1.1.0] - 2026-07-23&quot;">​</a></h2><h2 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h2><ul><li>Add portable Codex marketplace integration with standalone scaffold, doctor, render, and shared JSVision guidance skills.</li></ul><h2 id="changed" tabindex="-1">Changed <a class="header-anchor" href="#changed" aria-label="Permalink to &quot;Changed&quot;">​</a></h2><ul><li>Enforce source-impact, API, distribution, and release-version synchronization.</li><li>Stop implying the browser host is installable in documentation.</li><li>Write the Install &amp; packages guide, replacing placeholder with real content and retiring stale reference guides.</li></ul><h2 id="fixed" tabindex="-1">Fixed <a class="header-anchor" href="#fixed" aria-label="Permalink to &quot;Fixed&quot;">​</a></h2><ul><li>Generate starters that typecheck and guard the templates to prevent errors.</li><li>Give the data-grid guide a title distinct from the component page to ensure unique titles for SEO.</li><li>Run the docs-build gate under js-yaml v5 to avoid import errors.</li></ul><h2 id="_1-0-0-2026-07-22" tabindex="-1">[1.0.0] - 2026-07-22 <a class="header-anchor" href="#_1-0-0-2026-07-22" aria-label="Permalink to &quot;[1.0.0] - 2026-07-22&quot;">​</a></h2><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Added three new live showcase apps: effects, calculator, and Game of Life.</li><li>Added amiga-clock and matrix showcase apps with animations to the Apps section.</li><li>Introduced JSDoc @example compile guard with a shrink-only allowlist.</li></ul><h3 id="changed-1" tabindex="-1">Changed <a class="header-anchor" href="#changed-1" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Restructured the Guide sidebar into five groups and created 19 new guide stub pages.</li><li>Sorted the Apps sidebar list alphabetically.</li><li>Widened the documentation layout and uncapped the article column.</li><li>Rewrote the introduction to include two live examples focused on JSVision for newcomers.</li><li>Enhanced documentation for the framework-wide clipboard, fixing stale Editor claims.</li></ul><h3 id="fixed-1" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-1" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Restored three spec oracles and corrected misleading comments.</li><li>Tightened layout-erasure resets to interface specifications, closing potential issues.</li><li>Hardened the @example guard&#39;s cache key and build check to remove latent traps.</li><li>Increased the test timeout for docs-site to address cold-compiler flakes on Windows.</li></ul><h3 id="deprecated" tabindex="-1">Deprecated <a class="header-anchor" href="#deprecated" aria-label="Permalink to &quot;Deprecated&quot;">​</a></h3><ul><li>No entries.</li></ul><h3 id="removed" tabindex="-1">Removed <a class="header-anchor" href="#removed" aria-label="Permalink to &quot;Removed&quot;">​</a></h3><ul><li>No entries.</li></ul><h3 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h3><ul><li>No entries.</li></ul><h2 id="_0-2-0-2026-07-12" tabindex="-1">[0.2.0] - 2026-07-12 <a class="header-anchor" href="#_0-2-0-2026-07-12" aria-label="Permalink to &quot;[0.2.0] - 2026-07-12&quot;">​</a></h2><p>Changed:</p><ul><li>Upgraded all development and build dependencies while retaining TypeScript at version 5.x to avoid compatibility issues with related tools.</li></ul><h2 id="_0-1-1-2026-07-12" tabindex="-1">[0.1.1] - 2026-07-12 <a class="header-anchor" href="#_0-1-1-2026-07-12" aria-label="Permalink to &quot;[0.1.1] - 2026-07-12&quot;">​</a></h2><p>Fixed:</p><ul><li>Added <code>repository</code> field to private packages for provenance requirements.</li><li>Aligned docs-site version to match the monorepo version 0.1.0.</li></ul>',29)])])}const m=a(r,[["render",o]]);export{p as __pageData,m as default};
